using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed metadata retrieval — returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");
Console.WriteLine($"  Kind: {personInfo.Kind}");

// 2) Probe without throwing — TryGetTypeInfo returns false if unavailable
//    Here we use options with NO resolver, so nothing is resolvable.
var empty = new JsonSerializerOptions { TypeInfoResolver = null };

if (empty.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info))
{
    Console.WriteLine($"Found metadata: {info!.Type.Name}");
}
else
{
    Console.WriteLine("No metadata for Person (resolver is null) — no exception thrown.");
}

// Also show TryGetTypeInfo succeeding with the configured options
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info2))
{
    Console.WriteLine($"TryGetTypeInfo succeeded: {info2!.Type.Name}");
}

public record Person(string Name, int Age);

